const result = $json.chart?.result?.[0];

if (!result) {
  throw new Error('Yahoo returned no chart result');
}

const meta = result.meta ?? {};
const yahooSymbol = meta.symbol;

if (!yahooSymbol) {
  throw new Error('Yahoo response has no symbol');
}

// Match the Yahoo response to the correct portfolio entry.
// This avoids n8n item-linking mixing prices between tickers.
const stocks = $('Stock List')
  .all()
  .map(item => item.json);

const stock = stocks.find(item =>
  String(item.symbol).trim().toUpperCase() ===
  String(yahooSymbol).trim().toUpperCase()
);

if (!stock) {
  throw new Error(
    `Could not find ${yahooSymbol} in Stock List`
  );
}

const timestamps = result.timestamp ?? [];
const quote = result.indicators?.quote?.[0] ?? {};
const closes = quote.close ?? [];
const volumes = quote.volume ?? [];

if (
  timestamps.length === 0 ||
  closes.length === 0 ||
  volumes.length === 0
) {
  throw new Error(
    `Yahoo returned incomplete data for ${yahooSymbol}`
  );
}

// Build valid historical rows.
const rows = timestamps
  .map((time, index) => ({
    time,
    close: closes[index],
    volume: volumes[index],
  }))
  .filter(row =>
    Number.isFinite(row.time) &&
    Number.isFinite(row.close) &&
    Number.isFinite(row.volume)
  )
  .sort((a, b) => a.time - b.time);

// Remove duplicate timestamps.
// If duplicates exist, keep the row with the highest volume,
// which is normally the most complete candle.
const rowsByTimestamp = new Map();

for (const row of rows) {
  const existing = rowsByTimestamp.get(row.time);

  if (!existing || row.volume >= existing.volume) {
    rowsByTimestamp.set(row.time, row);
  }
}

const valid = [...rowsByTimestamp.values()]
  .sort((a, b) => a.time - b.time);

if (valid.length < 2) {
  throw new Error(
    `Not enough valid price rows for ${yahooSymbol}`
  );
}

const today = valid.at(-1);
const yesterday = valid.at(-2);

const currentPrice = today.close;
const previousClose = yesterday.close;

// Use approximately three months of previous trading sessions.
// 63 trading days is roughly three calendar months.
const previousVolumeRows = valid.slice(-64, -1);

if (previousVolumeRows.length === 0) {
  throw new Error(
    `Not enough volume history for ${yahooSymbol}`
  );
}

const previousVolumes = previousVolumeRows.map(
  row => row.volume
);

const averageVolume3m =
  previousVolumes.reduce(
    (sum, value) => sum + value,
    0
  ) / previousVolumes.length;

const dailyChangePercent =
  ((currentPrice - previousClose) / previousClose) * 100;

const volumeDeviationPercent =
  averageVolume3m > 0
    ? ((today.volume - averageVolume3m) /
        averageVolume3m) *
      100
    : 0;

const buyPrice = Number(stock.buyPrice);

const stopLossTriggered =
  Number.isFinite(buyPrice) &&
  currentPrice <= buyPrice * 0.93;

const unrealizedReturnPercent =
  Number.isFinite(buyPrice)
    ? ((currentPrice - buyPrice) / buyPrice) * 100
    : null;

const priceVsBuy =
  !Number.isFinite(buyPrice)
    ? "unknown"
    : currentPrice > buyPrice
      ? "above"
      : currentPrice < buyPrice
        ? "below"
        : "equal";

const stopLossPrice =
  Number.isFinite(buyPrice)
    ? buyPrice * 0.93
    : null;

return {
  json: {
    symbol: yahooSymbol,
    currency: meta.currency ?? null,

    buyPrice: Number.isFinite(buyPrice)
      ? buyPrice
      : null,

    currentPrice,
    previousClose,

    latestTimestamp: today.time,
    latestDate: new Date(
      today.time * 1000
    ).toISOString(),

    dailyChangePercent,
    dailyVolume: today.volume,

    averageVolume3m,
    volumeDeviationPercent,
    priceVsBuy,
    unrealizedReturnPercent,
    stopLossPrice,
    stopLossTriggered,

    highVolumeDown:
      volumeDeviationPercent > 10 &&
      dailyChangePercent < 0,

    stopLossTriggered,

    historyRows: valid.length,

    // Used by the following MACD node.
    closes: valid.map(row => row.close),
  },
};

const closes = $json.closes.filter(Number.isFinite);

if (closes.length < 35) {
  throw new Error(`Not enough price data for MACD: ${closes.length} values`);
}

function ema(values, period) {
  const multiplier = 2 / (period + 1);
  const result = [values[0]];

  for (let i = 1; i < values.length; i++) {
    result.push(
      values[i] * multiplier +
      result[i - 1] * (1 - multiplier)
    );
  }

  return result;
}

const ema12 = ema(closes, 12);
const ema26 = ema(closes, 26);

const macdSeries = closes.map(
  (_, index) => ema12[index] - ema26[index]
);

const signalSeries = ema(macdSeries, 9);

const lastIndex = closes.length - 1;
const previousIndex = lastIndex - 1;

const macd = macdSeries[lastIndex];
const signal = signalSeries[lastIndex];
const histogram = macd - signal;

const previousMacd = macdSeries[previousIndex];
const previousSignal = signalSeries[previousIndex];
const previousHistogram = previousMacd - previousSignal;

let crossover = "none";

if (previousMacd <= previousSignal && macd > signal) {
  crossover = "bullish";
}

if (previousMacd >= previousSignal && macd < signal) {
  crossover = "bearish";
}

return {
  json: {
    ...$json,

    macd: Number(macd.toFixed(4)),
    macdSignal: Number(signal.toFixed(4)),
    macdHistogram: Number(histogram.toFixed(4)),

    macdState: macd > signal ? "bullish" : "bearish",
    macdCrossover: crossover,
    macdMomentumIncreasing: histogram > previousHistogram,
  },
};

const stocks = $input.all().map(item => {
  // Do not save the full three-month price array
  const { closes, ...result } = item.json;
  return result;
});

const now = new Date();

const date = now.toLocaleDateString('en-CA', {
  timeZone: 'Europe/Copenhagen',
});

return [
  {
    json: {
      fileName: `portfolio-${date}.json`,
      content: JSON.stringify(
        {
          generatedAt: now.toISOString(),
          date,
          stocks,
        },
        null,
        2
      ),
    },
  },
];

const choice = $json.choices?.[0];
const analysis = choice?.message?.content;

if (!analysis) {
  throw new Error('No LLM response found');
}

const source = $('Prepare LLM Input').item.json;

return {
  json: {
    symbol: source.symbol,
    stockData: source.stockData,
    analysis: analysis.trim(),
    finishReason: choice.finish_reason ?? 'unknown',
    completionTokens: $json.usage?.completion_tokens ?? null,
  },
};

const now = new Date();

const date = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Europe/Copenhagen',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
}).format(now);

return {
  json: {
    fileName: `analysis-${date}.json`,
    content: JSON.stringify(
      {
        generatedAt: $json.generatedAt,
        stocks: $json.stocks,
        analysis: $json.analysis,
      },
      null,
      2
    ),
  },
};

