const items = $input.all();

const sections = items.map(item => {
  const symbol = String(item.json.symbol ?? 'UNKNOWN');
  const lines = String(item.json.analysis ?? '')
    .trim()
    .split('\n');

  // Remove the symbol if the LLM already put it on the first line
  if (
    lines.length > 0 &&
    lines[0].trim().toUpperCase() === symbol.toUpperCase()
  ) {
    lines.shift();
  }

  return [
    symbol,
    lines.join('\n').trim(),
  ].join('\n');
});

const date = new Intl.DateTimeFormat('en-DK', {
  timeZone: 'Europe/Copenhagen',
  dateStyle: 'long',
}).format(new Date());

const telegramMessage = [
  `Portfolio report - ${date}`,
  '',
  sections.join('\n\n'),
].join('\n');

return [
  {
    json: {
      telegramMessage,
      stockCount: items.length,
      characters: telegramMessage.length,
    },
  },
];

const MAX_BYTES = 4000;
const original = String($json.telegramMessage ?? '');

function byteLength(value) {
  return new TextEncoder().encode(value).length;
}

if (byteLength(original) <= MAX_BYTES) {
  return {
    json: {
      ...$json,
      telegramMessage: original,
      wasTruncated: false,
      originalBytes: byteLength(original),
      finalBytes: byteLength(original),
    },
  };
}

// Reserve room for "..." and a possible closing HTML tag.
const RESERVED_BYTES = 20;

let truncated = '';

for (const character of original) {
  const candidate = truncated + character;

  if (
    byteLength(candidate) + RESERVED_BYTES >
    MAX_BYTES
  ) {
    break;
  }

  truncated = candidate;
}

// Prefer ending at a complete line.
const lastNewline = truncated.lastIndexOf('\n');

if (lastNewline > truncated.length * 0.7) {
  truncated = truncated.slice(0, lastNewline);
}

// Remove an incomplete HTML tag.
if (
  truncated.lastIndexOf('<') >
  truncated.lastIndexOf('>')
) {
  truncated = truncated.slice(
    0,
    truncated.lastIndexOf('<')
  );
}

// Remove an incomplete HTML entity such as "&amp".
if (
  truncated.lastIndexOf('&') >
  truncated.lastIndexOf(';')
) {
  truncated = truncated.slice(
    0,
    truncated.lastIndexOf('&')
  );
}

// Close an open bold tag if truncation occurred inside one.
const openBoldTags =
  (truncated.match(/<b>/g) ?? []).length;

const closedBoldTags =
  (truncated.match(/<\/b>/g) ?? []).length;

if (openBoldTags > closedBoldTags) {
  truncated += '</b>';
}

truncated = truncated.trimEnd() + '...';

return {
  json: {
    ...$json,
    telegramMessage: truncated,
    wasTruncated: true,
    originalBytes: byteLength(original),
    finalBytes: byteLength(truncated),
  },
};
